import { groupBy } from '../../src/groupby.mjs';
import test from 'node:test';
import assert from 'node:assert';
test('golden group', () => {
  assert.deepStrictEqual(groupBy([], () => 'k'), {});
  assert.deepStrictEqual(groupBy([1.1, 2.2, 1.9], Math.floor), { 1: [1.1, 1.9], 2: [2.2] });
  const r = groupBy(['a', 'bb', 'cc', 'd'], (s) => s.length);
  assert.deepStrictEqual(r, { 1: ['a', 'd'], 2: ['bb', 'cc'] });
});
